  ('police-b20a8cf8-moex-00554', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '下列何者為纖維鑑定中最關鍵與重要的步驟？', '["以顯微鏡比對樣品的直徑與顏色", "判定纖維是人造或天然纖維", "是否含有長鏈狀的高分子聚合物", "分析樣品的個化性特徵（individualcharacteristics）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00555', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '現場發現之骨骼遺骸（sketetalremains），經法醫人類學家（forensicanthopoligist）鑑定後確認為 股骨（femur）。以骨骼遺骸推估死者身高，下列敘述何者正確？', '["對於未知人類學人種的股骨遺骸，無法以公式來推估死者身高", "除了股骨外，也可以採用肱骨（humerus）來推估死者身高", "對於不同人類學的骨骼遺骸，可採用相同的計算公式來推估死者身高", "不同人類學性別的股骨遺骸，須採用相同的計算公式來推估死者身高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00556', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '以眼球液（vitreoushumor）中鉀離子濃度推估死亡時間（postmorteminterval），下列敘述何者正確？', '["同時採集兩眼之眼球液檢體，進行兩者之鉀離子濃度平均值計算得知", "死亡時間與鉀離子濃度成反比的情形", "鉀離子的產生是由於眼球內部細胞在死亡之後釋放鉀離子至眼球液中", "鉀離子濃度不受到現場溫度變化的影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00557', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '對於粒線體DNA（MitochondrialDNA）下列敘述何者正確？', '["可用於只有父系的DNA能比對的檢體", "可用於所需鑑別力大於短重複序列（shorttandemrepeat,STR）的檢體", "可用於無法以核DNA分型（DNAtyping）的檢體", "可用於只有微量DNA能比對的檢體"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00558', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '關於蒐集物證的過程，下列敘述何者正確？', '["縣市警察局分局長主責確保證物監管鏈（chainofcustody）的完整", "法醫應在現場監督物證的蒐集", "檢察官應在現場監督物證的蒐集", "所有觀察結果應由現場勘查人員藉由攝影、測繪以及筆記紀錄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00559', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '下列那一種的血跡型態（bloodstainpattern）含有氧氣與氣泡以及顏色較淺？', '["鈍力創傷（bluntforcetramawound）的血跡", "跑步時留下的血跡", "以雙氧水稀釋的血跡", "因內傷而從口鼻流出的血跡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00560', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '以偏光顯微鏡（polarizedlightmicroscopy）判定證物是否具有非均向性（anisotropic），下列敘述 何者正確？', '["將起偏鏡與檢偏鏡設定於互相平行的位置，並旋轉樣品一圈，當消光現象於4個特定角度產生 時，則可判定其為具有雙折射性的非均向樣品", "完成柯勒照明（Köhlerillumination）設定即可判定，並旋轉樣品一圈，當消光現象於4個特定 角度產生時，則可判定其為具有雙折射性的非均向樣品", "將起偏鏡與檢偏鏡設定於互相垂直的位置，並旋轉樣品一圈，當消光現象於4個特定角度產生 時，則可判定其為具有雙折射性的非均向樣品", "將起偏鏡與檢偏鏡設定於互相垂直的位置，並旋轉樣品一圈，當無法觀察到消光現象時，則可 判定其為具有雙折射性的非均向樣品"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00561', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '當外力作用在玻璃板的一側時，玻璃的彈性使其表面可以往施力方向彎曲，一旦外力超過彈性極 限，玻璃就會開始破裂。關於受撞擊點附近所產生的放射狀裂痕（radialcrack）上的應力痕（stressmark）， 下列敘述何者正確？', '["受撞擊面的應力（stress）只作用在受撞擊面", "受撞擊面的應力痕以曲線方向延伸至受撞擊面的背面，並與該平面形成90度", "受撞擊面的應力痕以平行方向延伸，無法抵達受撞擊面的背面", "受撞擊面的應力痕以平行方向延伸至受撞擊面的背面"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00562', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '關於古柯鹼鹽酸鹽（cocaineHCl）及古柯鹼游離鹼（cocainefreebase）的敘述，下列何者正確？', '["古柯鹼游離鹼的熔點比古柯鹼鹽酸鹽要來得高", "古柯鹼鹽酸鹽與碳酸氫鈉反應可產生古柯鹼游離鹼", "兩者無法以傅立葉轉換紅外光譜（Fourier-transforminfraredspectroscopy,FTIR）進行區分", "兩者可以使用紫外-可見光光譜（Ultraviolet–visiblespectroscopy,UV-Vis）進行區分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00563', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '當爆炸現場殘跡經過顯微鏡鏡檢之後，下一步可進行的分析是？', '["以X射線繞射儀（X-raydiffractometer,XRD）來找出爆裂物的有機物成分", "藉由溶解度的不同，以丙酮洗滌現場殘跡，將爆裂物與現場殘跡分離", "以分光光譜儀分析爆裂物顏色", "以低倍率顯微鏡檢視爆炸過程"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
